import{_ as s,C as d,o as t,c as n,a5 as o,b as i,w as r,a as c,E as h,a6 as l}from"./chunks/framework.BwcYdGwU.js";const w=JSON.parse('{"title":"OpenFGA","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/openfga.md","filePath":"reference/components/openfga.md"}'),p={name:"reference/components/openfga.md"};function u(m,e,f,g,b,A){const a=d("Mermaid");return t(),n("div",null,[e[1]||(e[1]=o('<h1 id="openfga" tabindex="-1">OpenFGA <a class="header-anchor" href="#openfga" aria-label="Permalink to &quot;OpenFGA&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>OpenFGA is the relationship-based authorization engine used by Platform Mesh. It stores the authorization models and relationship tuples that describe who owns, belongs to, or can operate on Platform Mesh organizations, accounts, namespaces, and API resources.</p><p>Platform Mesh uses OpenFGA as the durable policy graph behind <a href="/pr-preview/pr-192/concepts/security/authorization.html">relationship-based authorization</a>. The <a href="./security-operator.html">Security operator</a> and <a href="./iam-service.html">IAM service</a> write authorization data into OpenFGA. The <a href="./rebac-authz-webhook.html">rebac-authz-webhook</a> and IAM service read that data at request time.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>This component is in alpha. APIs, deployment wiring, and the Platform Mesh authorization model may change on short notice, including breaking changes.</p></div><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>At runtime OpenFGA exposes the following endpoints and dependencies:</p><table tabindex="0"><thead><tr><th>Runtime dependency</th><th>Default</th><th>Role</th></tr></thead><tbody><tr><td>gRPC API</td><td>Port <code>8081</code></td><td>Used by in-cluster Platform Mesh clients such as the Security operator, IAM service, and <code>rebac-authz-webhook</code>.</td></tr><tr><td>HTTP API</td><td>Port <code>8080</code></td><td>OpenFGA HTTP API endpoint.</td></tr><tr><td>Playground</td><td>Port <code>3000</code></td><td>Browser UI for inspecting and querying OpenFGA.</td></tr><tr><td>Metrics</td><td>Port <code>2112</code></td><td>OpenFGA metrics endpoint.</td></tr><tr><td>Datastore</td><td>Postgres</td><td>Durable storage for stores, authorization models, and relationship tuples.</td></tr><tr><td>Database migrations</td><td><code>datastore.applyMigrations: true</code>, <code>datastore.migrationType: initContainer</code></td><td>Runs OpenFGA schema migrations before the OpenFGA container starts.</td></tr><tr><td>Experimental APIs</td><td><code>OPENFGA_EXPERIMENTALS=enable-list-users</code></td><td>Enables <code>ListUsers</code>, which the IAM service uses for role-assignment views.</td></tr></tbody></table><p>OpenFGA does not own Platform Mesh CRDs. Platform Mesh represents OpenFGA state through <code>Store</code> and <code>AuthorizationModel</code> resources from the Security operator API, and the Security operator reconciles those resources into OpenFGA.</p><p>OpenFGA stores and evaluates authorization data. It does not create Platform Mesh stores, assemble authorization models, write system tuples, resolve kcp workspace context, or interpret Kubernetes authorization requests; those responsibilities stay with Platform Mesh components.</p><h2 id="how-it-fits-into-platform-mesh" tabindex="-1">How it fits into Platform Mesh <a class="header-anchor" href="#how-it-fits-into-platform-mesh" aria-label="Permalink to &quot;How it fits into Platform Mesh&quot;">​</a></h2><p>Platform Mesh keeps the OpenFGA service separate from the components that initialize, mutate, and consume authorization data:</p><table tabindex="0"><thead><tr><th>Component</th><th>Role</th></tr></thead><tbody><tr><td><a href="./security-operator.html">Security operator</a></td><td>Creates OpenFGA stores, writes authorization models, and manages initial and system-owned tuples.</td></tr><tr><td><a href="./iam-service.html">IAM service</a></td><td>Reads role assignments and writes user-to-role tuples for IAM workflows.</td></tr><tr><td><a href="./rebac-authz-webhook.html">rebac-authz-webhook</a></td><td>Converts kcp <code>SubjectAccessReview</code> requests into OpenFGA <code>Check</code> calls.</td></tr><tr><td><a href="./account-operator.html">Account operator</a></td><td>Creates account metadata and propagates the organization&#39;s OpenFGA store ID through <code>AccountInfo</code>; it does not call OpenFGA directly.</td></tr><tr><td><a href="./platform-mesh-operator.html">Platform Mesh operator</a></td><td>Installs the OpenFGA Helm release through the component chart; it does not call OpenFGA at runtime.</td></tr><tr><td>OpenFGA</td><td>Stores and evaluates the relationship graph.</td></tr></tbody></table>',13)),(t(),i(l,null,{default:r(()=>[h(a,{id:"mermaid-191",class:"mermaid",graph:"flowchart%20LR%0A%20%20subgraph%20designTime%5B%22Design%20time%22%5D%0A%20%20%20%20securityOperator%5B%22Security%20operator%22%5D%20--%3E%7C%22CreateStore%20%2F%20WriteAuthorizationModel%20%2F%20Write%20tuples%22%7C%20openfga%5B(%22OpenFGA%20stores%22)%5D%0A%20%20%20%20iamWriter%5B%22IAM%20service%22%5D%20--%3E%7C%22Write%20role-assignment%20tuples%22%7C%20openfga%0A%20%20end%0A%0A%20%20subgraph%20runtime%5B%22Runtime%22%5D%0A%20%20%20%20webhook%5B%22rebac-authz-webhook%22%5D%20--%3E%7C%22Check%22%7C%20openfga%0A%20%20%20%20iamReader%5B%22IAM%20service%22%5D%20--%3E%7C%22Read%20%2F%20ListUsers%22%7C%20openfga%0A%20%20end%0A%0A%20%20openfga%20--%3E%20postgres%5B%22openfga-postgres%20(StatefulSet)%22%5D%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="upstream-concepts-and-dependencies" tabindex="-1">Upstream concepts and dependencies <a class="header-anchor" href="#upstream-concepts-and-dependencies" aria-label="Permalink to &quot;Upstream concepts and dependencies&quot;">​</a></h2><p>OpenFGA brings these upstream authorization concepts into Platform Mesh:</p><table tabindex="0"><thead><tr><th>Concept</th><th>Platform Mesh page</th><th>Role here</th></tr></thead><tbody><tr><td><a href="https://openfga.dev/docs/concepts#what-is-a-store" target="_blank" rel="noreferrer">OpenFGA stores</a></td><td><a href="./security-operator.html">Security operator</a></td><td>Authorization boundaries for the shared <code>root:orgs</code> workspace and per-organization workspaces.</td></tr><tr><td><a href="https://openfga.dev/docs/concepts#what-is-an-authorization-model" target="_blank" rel="noreferrer">Authorization models</a></td><td><a href="./security-operator.html">Security operator</a></td><td>Define the object types, relations, and permissions used by Platform Mesh authorization checks.</td></tr><tr><td><a href="https://openfga.dev/docs/concepts#what-is-a-relationship-tuple" target="_blank" rel="noreferrer">Relationship tuples</a></td><td><a href="/pr-preview/pr-192/concepts/identity-and-authorization.html">Identity and authorization</a></td><td>Store ownership, membership, role assignment, and resource relationships.</td></tr><tr><td><a href="https://openfga.dev/docs/getting-started/perform-check" target="_blank" rel="noreferrer"><code>Check</code></a></td><td><a href="./rebac-authz-webhook.html">rebac-authz-webhook</a></td><td>Runtime authorization operation used by the webhook for kcp requests.</td></tr><tr><td><a href="https://openfga.dev/docs/interacting/relationship-queries" target="_blank" rel="noreferrer"><code>ListUsers</code></a></td><td><a href="./iam-service.html">IAM service</a></td><td>IAM role-assignment views rely on this API, so Platform Mesh enables <code>OPENFGA_EXPERIMENTALS=enable-list-users</code>.</td></tr><tr><td>Postgres datastore</td><td><a href="#deployment-and-platform-mesh-wiring">Deployment and Platform Mesh wiring</a></td><td>Durable storage for OpenFGA stores, authorization models, and tuples.</td></tr></tbody></table><h2 id="stores-and-authorization-model-layout" tabindex="-1">Stores and authorization model layout <a class="header-anchor" href="#stores-and-authorization-model-layout" aria-label="Permalink to &quot;Stores and authorization model layout&quot;">​</a></h2><p>Platform Mesh uses OpenFGA stores as authorization boundaries:</p><table tabindex="0"><thead><tr><th>Store</th><th>Purpose</th></tr></thead><tbody><tr><td><code>orgs</code></td><td>Shared store for the <code>root:orgs</code> workspace. The authorization webhook uses this store when checking requests against the organizations workspace.</td></tr><tr><td>One store per organization</td><td>Holds the relationship graph for that organization&#39;s account workspaces and resources. Store names match organization names, and <code>Store.status.storeId</code> contains the OpenFGA store ID.</td></tr></tbody></table><p>Each store&#39;s authorization model is assembled by the Security operator from several inputs:</p><ol><li>The core module configured in the <code>security-operator</code> Helm chart.</li><li>Kubernetes and kcp API discovery for core resources.</li><li>Privileged RBAC-derived model fragments for resources such as Kubernetes RBAC objects.</li><li><code>AuthorizationModel</code> resources created for bound provider APIs.</li></ol><p>The Security operator writes the merged model to OpenFGA using schema version <code>1.2</code> and records the resulting model ID in <code>Store.status.authorizationModelId</code>. See the <a href="./security-operator.html">Security operator</a> reference for the <code>Store</code> and <code>AuthorizationModel</code> resource shapes.</p><p>For the <code>Store</code> CRD fields and lifecycle, see <a href="/pr-preview/pr-192/reference/resources/iamstore-resource.html">IAM Store resource</a>.</p><h2 id="data-writers" tabindex="-1">Data writers <a class="header-anchor" href="#data-writers" aria-label="Permalink to &quot;Data writers&quot;">​</a></h2><h3 id="security-operator-stores-and-authorization-models" tabindex="-1">Security operator: stores and authorization models <a class="header-anchor" href="#security-operator-stores-and-authorization-models" aria-label="Permalink to &quot;Security operator: stores and authorization models&quot;">​</a></h3><p>The Security operator is the main owner of Platform Mesh authorization data in OpenFGA.</p><p>Its <code>Store</code> subroutine reconciles Platform Mesh <code>Store</code> custom resources to OpenFGA stores. If a <code>Store</code> resource has no <code>status.storeId</code>, the subroutine first searches OpenFGA by store name and then creates an OpenFGA store if none exists. When a Platform Mesh <code>Store</code> resource is deleted, its finalizer deletes the matching OpenFGA store after dependent <code>AuthorizationModel</code> resources are gone.</p><p>The <code>AuthorizationModel</code> subroutine turns the <code>Store</code> core module plus all related <code>AuthorizationModel</code> extensions into a single OpenFGA authorization model. For organization stores other than <code>orgs</code>, it also discovers Kubernetes and kcp API resources in the organization workspace and generates model fragments for them.</p><h3 id="security-operator-initial-and-system-tuples" tabindex="-1">Security operator: initial and system tuples <a class="header-anchor" href="#security-operator-initial-and-system-tuples" aria-label="Permalink to &quot;Security operator: initial and system tuples&quot;">​</a></h3><p>During organization workspace initialization, the Security operator creates the organization <code>Store</code> resource in <code>root:orgs</code> and seeds it with the initial owner/member tuples for the organization creator.</p><p>For account workspaces below an organization, the <code>AccountTuplesSubroutine</code> writes tuples that connect the account to its parent account and creator. During termination, it removes tuples that reference the account and account-specific roles.</p><p>The Security operator also writes tuples for other security workflows, including API export binding permissions from <code>APIExportPolicy</code> resources and invite-related access setup.</p><h3 id="iam-service-role-assignments" tabindex="-1">IAM service: role assignments <a class="header-anchor" href="#iam-service-role-assignments" aria-label="Permalink to &quot;IAM service: role assignments&quot;">​</a></h3><p>The IAM service writes user role assignments into OpenFGA for IAM UI and GraphQL workflows. Assigning a role writes tuples such as <code>role:&lt;resource-type&gt;/&lt;cluster&gt;/&lt;resource&gt;/&lt;role&gt;#assignee -&gt; user:&lt;id&gt;</code>. Removing a role deletes the corresponding tuple.</p><p>The IAM service looks up the correct organization store before applying these changes, so role assignment data lands in the organization-specific OpenFGA store.</p><h3 id="non-writers" tabindex="-1">Non-writers <a class="header-anchor" href="#non-writers" aria-label="Permalink to &quot;Non-writers&quot;">​</a></h3><p>The Platform Mesh operator installs and configures OpenFGA through Helm, but it does not call the OpenFGA API at runtime.</p><p>The Account operator does not call OpenFGA directly. It creates and updates <code>AccountInfo</code> resources. For organization accounts, the OpenFGA store ID in <code>AccountInfo.spec.fga.store.id</code> is supplied by the external workspace initialization flow. For child accounts, the Account operator copies that ID from the parent <code>AccountInfo</code> so account metadata keeps pointing back to the organization&#39;s authorization store.</p><h2 id="data-consumers" tabindex="-1">Data consumers <a class="header-anchor" href="#data-consumers" aria-label="Permalink to &quot;Data consumers&quot;">​</a></h2><h3 id="rebac-authz-webhook" tabindex="-1">rebac-authz-webhook <a class="header-anchor" href="#rebac-authz-webhook" aria-label="Permalink to &quot;rebac-authz-webhook&quot;">​</a></h3><p>The authorization webhook is the request-time consumer for kcp authorization. kcp sends it <code>SubjectAccessReview</code> requests, and the webhook calls OpenFGA <code>Check</code> against either the shared <code>orgs</code> store or the organization store for the target account workspace.</p><p>The webhook returns <code>allowed: true</code> when OpenFGA allows the request. When OpenFGA does not allow the request, or the webhook cannot complete the check, it returns no opinion. In Platform Mesh the webhook is last in the kcp authorizer chain, so no opinion is effectively a deny. See <a href="./rebac-authz-webhook.html">rebac-authz-webhook</a> for the full request flow.</p><h3 id="iam-service" tabindex="-1">IAM service <a class="header-anchor" href="#iam-service" aria-label="Permalink to &quot;IAM service&quot;">​</a></h3><p>The IAM service uses OpenFGA to list users assigned to roles, check existing role assignments, and apply role changes. The OpenFGA <code>ListUsers</code> API is part of this flow, which is why the Platform Mesh OpenFGA deployment enables the <code>enable-list-users</code> experimental feature.</p><h2 id="deployment-and-platform-mesh-wiring" tabindex="-1">Deployment and Platform Mesh wiring <a class="header-anchor" href="#deployment-and-platform-mesh-wiring" aria-label="Permalink to &quot;Deployment and Platform Mesh wiring&quot;">​</a></h2><p>OpenFGA is an upstream component, not a Platform Mesh-owned service repository. Platform Mesh consumes the upstream <a href="https://github.com/openfga/openfga" target="_blank" rel="noreferrer">openfga/openfga</a> Helm chart and image through OCM metadata in <a href="https://github.com/platform-mesh/helm-charts" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a>.</p><p>The <code>platform-mesh-operator-components</code> chart defines the OpenFGA service entry under <code>services.openfga</code>. Important defaults:</p><table tabindex="0"><thead><tr><th>Value</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>services.openfga.enabled</code></td><td><code>true</code></td><td>Includes OpenFGA in a standard Platform Mesh installation.</td></tr><tr><td><code>services.openfga.external</code></td><td><code>true</code></td><td>Treats OpenFGA as an external component resolved through OCM metadata.</td></tr><tr><td><code>services.openfga.helmRepo</code></td><td><code>true</code></td><td>Renders a Flux <code>HelmRelease</code> that uses a <code>HelmRepository</code> source.</td></tr><tr><td><code>services.openfga.suspend</code></td><td><code>true</code></td><td>Starts suspended until image resources are resolved by the component flow.</td></tr><tr><td><code>services.openfga.values.image.repository</code></td><td><code>openfga/openfga</code></td><td>Upstream OpenFGA image repository.</td></tr><tr><td><code>services.openfga.values.datastore.engine</code></td><td><code>postgres</code></td><td>Uses Postgres as the OpenFGA datastore.</td></tr><tr><td><code>services.openfga.values.datastore.applyMigrations</code></td><td><code>true</code></td><td>Runs OpenFGA database migrations.</td></tr><tr><td><code>services.openfga.values.datastore.migrationType</code></td><td><code>initContainer</code></td><td>Runs migrations before the OpenFGA container starts.</td></tr><tr><td><code>services.openfga.values.postgresql.enabled</code></td><td><code>true</code></td><td>Deploys the bundled Postgres subchart.</td></tr></tbody></table><p>The same component chart wires other Platform Mesh services to OpenFGA:</p><table tabindex="0"><thead><tr><th>Consumer</th><th>Default OpenFGA address</th></tr></thead><tbody><tr><td>Security operator</td><td><code>openfga.platform-mesh-system.svc.cluster.local:8081</code></td></tr><tr><td>rebac-authz-webhook</td><td><code>openfga:8081</code></td></tr><tr><td>IAM service</td><td><code>openfga:8081</code></td></tr><tr><td>Account operator FGA subroutine config</td><td><code>openfga:8081</code></td></tr></tbody></table><p>The Account operator value is present for account subroutine configuration, but current account-operator code does not call OpenFGA directly.</p><p>The <code>infra</code> chart declares the service accounts that may write OpenFGA data:</p><table tabindex="0"><thead><tr><th>Value</th><th>Default principal</th></tr></thead><tbody><tr><td><code>openfga.rbac.writePrincipals[0]</code></td><td><code>cluster.local/ns/platform-mesh-system/sa/iam-service</code></td></tr><tr><td><code>openfga.rbac.writePrincipals[1]</code></td><td><code>cluster.local/ns/platform-mesh-system/sa/security-operator</code></td></tr><tr><td><code>openfga.rbac.writePrincipals[2]</code></td><td><code>cluster.local/ns/platform-mesh-system/sa/account-operator</code></td></tr></tbody></table><p>The Account operator principal is present in the infra defaults, but current account-operator code does not call OpenFGA directly.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The authoritative OpenFGA Helm values are the upstream chart values. Platform Mesh passes selected values through <code>services.openfga.values</code> in the <code>platform-mesh-operator-components</code> chart.</p><p>Important Platform Mesh defaults:</p><table tabindex="0"><thead><tr><th>Value</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>extraEnvVars[].OPENFGA_EXPERIMENTALS</code></td><td><code>enable-list-users</code></td><td>Enables <code>ListUsers</code> for IAM service role views.</td></tr><tr><td><code>log.level</code></td><td><code>info</code></td><td>OpenFGA log level.</td></tr><tr><td><code>replicaCount</code></td><td><code>1</code></td><td>Single replica by default.</td></tr><tr><td><code>autoscaling.enabled</code></td><td><code>false</code></td><td>Horizontal autoscaling disabled by default.</td></tr><tr><td><code>checkQueryCache.enabled</code></td><td><code>true</code></td><td>Enables OpenFGA check query caching.</td></tr><tr><td><code>checkQueryCache.limit</code></td><td><code>10000</code></td><td>Cache entry limit.</td></tr><tr><td><code>checkQueryCache.ttl</code></td><td><code>10s</code></td><td>Cache TTL.</td></tr><tr><td><code>telemetry.trace.enabled</code></td><td><code>false</code></td><td>OpenFGA trace export disabled by default.</td></tr><tr><td><code>telemetry.trace.otlp.endpoint</code></td><td><code>observability-opentelemetry-collector.observability.svc.cluster.local:4317</code></td><td>Default OTLP endpoint when tracing is enabled.</td></tr></tbody></table><p>OpenFGA clients are configured in their own component charts:</p><table tabindex="0"><thead><tr><th>Component</th><th>Configuration</th></tr></thead><tbody><tr><td>Security operator</td><td><code>fga.target</code>, plus <code>--fga-*</code> flags for store ID cache TTL and tuple relation names.</td></tr><tr><td>rebac-authz-webhook</td><td><code>openfga.url</code>, passed to <code>--openfga-addr</code>.</td></tr><tr><td>IAM service</td><td><code>openfga-grpc-addr</code> and <code>openfga-store-cache-ttl</code>.</td></tr></tbody></table><h2 id="local-setup" tabindex="-1">Local setup <a class="header-anchor" href="#local-setup" aria-label="Permalink to &quot;Local setup&quot;">​</a></h2><p>OpenFGA ships with the standard Platform Mesh local setup. For local access to the OpenFGA playground, see <a href="/pr-preview/pr-192/how-to-guides/access-openfga.html">Access the OpenFGA playground</a>.</p><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li>Upstream: <a href="https://github.com/openfga/openfga" target="_blank" rel="noreferrer">openfga/openfga</a></li><li>Platform Mesh configuration: <a href="https://github.com/platform-mesh/helm-charts" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-192/concepts/identity-and-authorization.html">Identity and authorization</a></li><li><a href="/pr-preview/pr-192/how-to-guides/access-openfga.html">Access OpenFGA</a></li><li><a href="./security-operator.html">Security operator</a></li><li><a href="./rebac-authz-webhook.html">rebac-authz-webhook</a></li></ul>',53))])}const P=s(p,[["render",u]]);export{w as __pageData,P as default};
